"""LRU (Least Recently Used) eviction policy for cache systems."""

import threading
from collections import OrderedDict
from typing import Any, Optional, Tuple


class LRUEvictionPolicy:
    """Thread-safe LRU eviction tracker.

    Tracks access order for cache keys and determines which entries
    to evict when capacity is reached.
    """

    def __init__(self, capacity: int = 10000):
        self._capacity = capacity
        self._order: OrderedDict[str, None] = OrderedDict()
        self._lock = threading.Lock()

    @property
    def capacity(self) -> int:
        return self._capacity

    @property
    def size(self) -> int:
        with self._lock:
            return len(self._order)

    def touch(self, key: str) -> None:
        """Mark a key as recently used."""
        with self._lock:
            if key in self._order:
                self._order.move_to_end(key)
            else:
                self._order[key] = None

    def remove(self, key: str) -> None:
        """Remove a key from tracking."""
        with self._lock:
            self._order.pop(key, None)

    def evict_one(self) -> Optional[str]:
        """Remove and return the least recently used key, or None if empty."""
        with self._lock:
            if not self._order:
                return None
            key, _ = self._order.popitem(last=False)
            return key

    def should_evict(self) -> bool:
        """Check if the cache has reached capacity."""
        with self._lock:
            return len(self._order) >= self._capacity

    def clear(self) -> None:
        """Clear all tracking data."""
        with self._lock:
            self._order.clear()

"""Control plane cache invalidation handler."""

import json
import logging
import fnmatch
from typing import Callable, Optional, Protocol

logger = logging.getLogger(__name__)


class CacheInvalidator(Protocol):
    """Protocol for cache objects that support invalidation."""

    def invalidate(self, domain: str) -> None:
        """Invalidate all cache entries for a specific domain."""
        ...

    def invalidate_pattern(self, pattern: str) -> None:
        """Invalidate cache entries matching a glob pattern."""
        ...

    def clear(self) -> None:
        """Clear the entire cache."""
        ...


class InvalidationHandler:
    """Processes cache invalidation signals from the control plane.

    Listens for invalidation messages on the WebSocket channel and
    dispatches them to registered cache instances.
    """

    def __init__(self):
        self._caches: list[CacheInvalidator] = []

    def register_cache(self, cache: CacheInvalidator) -> None:
        """Register a cache instance to receive invalidation signals."""
        self._caches.append(cache)

    def handle_message(self, message: str) -> None:
        """Process an invalidation message from the control plane.

        Message format:
            {"action": "invalidate", "domain": "example.com"}
            {"action": "invalidate_pattern", "pattern": "*.example.com"}
            {"action": "flush"}  # clear all caches
        """
        try:
            payload = json.loads(message)
            action = payload.get("action")

            if action == "invalidate":
                domain = payload["domain"]
                logger.info("Invalidating domain", extra={"domain": domain})
                for cache in self._caches:
                    cache.invalidate(domain)

            elif action == "invalidate_pattern":
                pattern = payload["pattern"]
                logger.info("Invalidating pattern", extra={"pattern": pattern})
                for cache in self._caches:
                    cache.invalidate_pattern(pattern)

            elif action == "flush":
                logger.warning("Flushing all caches")
                for cache in self._caches:
                    cache.clear()

            else:
                logger.error("Unknown invalidation action", extra={"action": action})

        except (json.JSONDecodeError, KeyError) as e:
            logger.error("Invalid invalidation message", extra={"error": str(e), "message": message})
